async findAllPaths(
  source: string,
  target: string,
  maxDepth: number = 5,
  options: TraversalOptions = {}
): Promise<AllPathsResult> {
  // Ensure graph is loaded
  await this.storage.loadGraph();

  // Validate entities exist
  if (!this.storage.hasEntity(source) || !this.storage.hasEntity(target)) {
    return { paths: [], pathsExplored: 0 };
  }

  const opts = { ...DEFAULT_OPTIONS, ...options };
  const allPaths: PathResult[] = [];
  const currentPath: string[] = [source];
  const currentRelations: Relation[] = [];
  const visited = new Set<string>([source]);
  let pathsExplored = 0;

  const dfsAllPaths = (current: string, depth: number) => {
    // Check cancellation at each recursion
    checkAborted(opts.signal, 'findAllPaths');

    if (depth > maxDepth) return;

    if (current === target && depth > 0) {
      allPaths.push({
        path: [...currentPath],
        length: currentPath.length - 1,
        relations: [...currentRelations],
      });
      pathsExplored++;
      opts.onProgress?.(allPaths.length);
      return;
    }

    // ... rest of existing DFS logic ...
  };

  try {
    dfsAllPaths(source, 0);
    return { paths: allPaths, pathsExplored };
  } catch (error) {
    if (error instanceof Error && error.message.includes('cancelled')) {
      return { paths: allPaths, cancelled: true, pathsExplored };
    }
    throw error;
  }
}

