codeSnippets.streamJSONLWithProgress:
async streamJSONL(
  graph: ReadonlyKnowledgeGraph,
  options?: StreamOptions
): Promise<StreamResult> {
  const start = Date.now();
  let bytesWritten = 0;
  let entitiesWritten = 0;
  let relationsWritten = 0;
  const total = graph.entities.length + graph.relations.length;

  const writeStream = createWriteStream(this.filePath);

  try {
    // Write entities with progress
    for (const entity of graph.entities) {
      // Check cancellation
      if (options?.signal?.aborted) {
        throw new Error('Export cancelled');
      }

      const line = JSON.stringify(entity) + '\n';
      writeStream.write(line);
      bytesWritten += Buffer.byteLength(line, 'utf-8');
      entitiesWritten++;

      // Report progress every 100 entities
      if (entitiesWritten % 100 === 0) {
        options?.onProgress?.(
          entitiesWritten,
          total,
          `Exported ${entitiesWritten} entities (${bytesWritten} bytes)`
        );
      }
    }

    // Notify start of relations phase
    options?.onProgress?.(entitiesWritten, total, 'Exporting relations...');

    // Write relations with progress
    for (const relation of graph.relations) {
      if (options?.signal?.aborted) {
        throw new Error('Export cancelled');
      }

      const line = JSON.stringify(relation) + '\n';
      writeStream.write(line);
      bytesWritten += Buffer.byteLength(line, 'utf-8');
      relationsWritten++;

      if (relationsWritten % 100 === 0) {
        options?.onProgress?.(entitiesWritten + relationsWritten, total);
      }
    }

    // Final progress
    options?.onProgress?.(total, total, 'Export complete');

    // Wait for stream to finish
    await new Promise<void>((resolve, reject) => {
      writeStream.end(() => resolve());
      writeStream.on('error', reject);
    });

    return {
      bytesWritten,
      entitiesWritten,
      relationsWritten,
      durationMs: Date.now() - start,
    };
  } catch (error) {
    // Close stream properly
    await new Promise<void>(resolve => writeStream.end(resolve));

    if (error instanceof Error && error.message.includes('cancelled')) {
      return {
        bytesWritten,
        entitiesWritten,
        relationsWritten,
        durationMs: Date.now() - start,
        cancelled: true,
      };
    }
    throw error;
  }
}

