import { describe, it, expect, beforeEach, afterEach } from 'vitest';
import { promises as fs } from 'fs';
import { join } from 'path';
import { tmpdir } from 'os';
import { EntityManager } from '../../src/core/EntityManager.js';
import { CompressionManager } from '../../src/features/CompressionManager.js';
import { IOManager } from '../../src/features/IOManager.js';
import { GraphStorage } from '../../src/core/GraphStorage.js';
import type { Entity } from '../../src/types/index.js';

describe('TaskScheduler Integration', () => {
  let testDir: string;
  let storage: GraphStorage;
  let entityManager: EntityManager;
  let compressionManager: CompressionManager;
  let ioManager: IOManager;

  beforeEach(async () => {
    testDir = await fs.mkdtemp(join(tmpdir(), 'task-scheduler-test-'));
    storage = new GraphStorage(join(testDir, 'test.jsonl'));
    entityManager = new EntityManager(storage);
    compressionManager = new CompressionManager(storage);
    ioManager = new IOManager(storage);
  });

  afterEach(async () => {
    await fs.rm(testDir, { recursive: true, force: true });
  });

  // Helper: Create test entities
  function createTestEntities(count: number): Entity[] {
    return Array.from({ length: count }, (_, i) => ({
      name: `Entity${i}`,
      entityType: 'test',
      observations: [`Observation for entity ${i}`]
    }));
  }

  // Helper: Collect progress updates
  function createProgressCollector(): {
    calls: [number, number, string | undefined][];
    callback: (c: number, t: number, m?: string) => void;
  } {
    const calls: [number, number, string | undefined][] = [];
    return {
      calls,
      callback: (c, t, m) => calls.push([c, t, m])
    };
  }

  // Helper: Create AbortController that aborts after delay
  function createDelayedAbort(ms: number): AbortController {
    const controller = new AbortController();
    setTimeout(() => controller.abort(), ms);
    return controller;
  }

  describe('EntityManager.createEntities', () => {
    it('should report progress during bulk creation', async () => {
      const { calls, callback } = createProgressCollector();
      const entities = createTestEntities(200);

      const result = await entityManager.createEntities(entities, {
        batchSize: 50,
        onProgress: callback
      });

      expect(result.cancelled).toBe(false);
      expect(result.result?.length).toBe(200);
      expect(calls.length).toBeGreaterThanOrEqual(4);
      // Progress should be monotonically increasing
      for (let i = 1; i < calls.length; i++) {
        expect(calls[i][0]).toBeGreaterThanOrEqual(calls[i-1][0]);
      }
    });

    it('should return partial results on cancellation', async () => {
      const controller = createDelayedAbort(50);
      const entities = createTestEntities(1000);

      const result = await entityManager.createEntities(entities, {
        batchSize: 25,
        signal: controller.signal
      });

      expect(result.cancelled).toBe(true);
      expect(result.processedCount).toBeLessThan(1000);
      expect(result.processedCount).toBeGreaterThan(0);
    });
  });

  describe('CompressionManager', () => {
    it('should report progress during duplicate detection', async () => {
      // Create entities with duplicates
      const entities = [
        ...createTestEntities(100),
        ...createTestEntities(100).map(e => ({ ...e, name: `Dup${e.name}` }))
      ];
      await entityManager.createEntities(entities);

      const { calls, callback } = createProgressCollector();
      const result = await compressionManager.findDuplicates({
        threshold: 0.8,
        onProgress: callback
      });

      expect(result.cancelled).toBe(false);
      expect(calls.length).toBeGreaterThan(0);
    });
  });

  describe('Combined Workflow', () => {
    it('should track progress through import -> compress -> export pipeline', async () => {
      const progressPhases: string[] = [];

      // Phase 1: Import
      const importData = JSON.stringify({
        entities: createTestEntities(100),
        relations: []
      });
      await ioManager.importGraph({
        format: 'json',
        data: importData,
        onProgress: (c, t, m) => {
          if (m && !progressPhases.includes('import')) {
            progressPhases.push('import');
          }
        }
      });

      // Phase 2: Compress
      await compressionManager.compressGraph({
        threshold: 0.9,
        onProgress: (c, t, m) => {
          if (!progressPhases.includes('compress')) {
            progressPhases.push('compress');
          }
        }
      });

      // Verify all phases were tracked
      expect(progressPhases).toContain('import');
      expect(progressPhases).toContain('compress');
    });
  });

  describe('Performance', () => {
    it('should have minimal overhead from progress callbacks', async () => {
      const entities = createTestEntities(500);

      // Time without progress
      const startNoProgress = Date.now();
      await entityManager.createEntities(entities);
      const timeNoProgress = Date.now() - startNoProgress;

      // Reset storage
      storage.clearCache();
      await fs.writeFile(join(testDir, 'test.jsonl'), '');

      // Time with progress
      const startWithProgress = Date.now();
      await entityManager.createEntities(entities, {
        onProgress: () => {}
      });
      const timeWithProgress = Date.now() - startWithProgress;

      // Progress overhead should be < 20% (generous for CI variability)
      const overhead = (timeWithProgress - timeNoProgress) / timeNoProgress;
      expect(overhead).toBeLessThan(0.2);
    });
  });
});
